head.b:skin:
/* --- Your CSS (from index.html) --- */

    body {
      text-align: center;
      font-family: system-ui !important;
      width: 95%;
      padding: 6px;
      margin: auto;
      font-weight: 500;
      direction: rtl;
    }

    select {
      height: 500px;
      font-family: inherit;
    }

    option {
      height: 30px;
      direction: rtl;
      text-align: right;
      padding: 7px;
      font-size: 14px;
      font-family: inherit;
      font-weight: 500;
    }

    #inputfile {
      /* padding: 11px;
  width: 100%;
  text-align: center; */
      font-size: 20px
    }

    #zero {
      width: 100%;
      text-align: center;
      margin-top: 20px;
    }

    textarea,
    textarea:disabled {
      width: 90%;
      border: 2px solid #3079ed;
      padding: 4px;
      font-weight: 500;
      font-size: 15px;
      text-align: right;
      direction: rtl;
      font-family: inherit;
      color: black;
      background: white;
    }

    button {
      margin: 5px;
      padding: 5px 12px 5px 12px;
      width: auto;
      text-align: center;
      font-size: 19px;
      font-weight: 300;
      color: #fffcfc;
      background: #3f51b5;
      border-radius: 5px;
      border: 5px;
      font-family: inherit;
      font-weight: inherit;
    }



    button:hover {
      background: #1a2a84;
      color: #fff;
      cursor: pointer;

    }

    div {
      /* width: 100%; */
      text-align: center
    }

    @media only screen and (max-width: 600px) {
      select {
        height: 50px;
        width: 100px;
        border-radius: 12px;
        direction: rtl;
        text-align: right;

      }

      #hideCombinationTestBtn {
        left: 20% !important;
        font-size: 20px;
      }

      #delbtn {
        font-size: 20px;
      }

      #HeaderP {
        margin-top: 40px;
      }

    }

    /* @media only screen and (max-width:600px) {
  select {
    height: 350px;
    border-radius: 12px;
    text-align: center;
    width: 95%;
  }
} */

    @media only screen and (min-width:600px) {
      #HbtnDiv {
        display: block;
        width: auto;
        position: fixed;
        right: 0;
        top: 2%;
      }
    }

    p {
      /* direction: ltr */
    }

    #TestSummary {
      display: inline-block;
      font-weight: 500;
      font-size: 17px;
      color: #fff;
      background-color: #3f51b5;
      border-radius: 2px;
      padding: 5px;
    }

    .CombinationResultContainer {
      display: block;
      overflow: hidden;
      background-color: #f1f1f1;
      transition: max-height 0.2s ease-out;

    }

    #deleteCombinationTestBtn {
      background-color: #F44336;
      cursor: pointer;
      position: absolute;
      left: 2.5%;
      width: fit-content;
      height: fit-content;
      padding: 4px;
      margin: 1px;
      font-size: 17px;
      font-weight: bold;
      border-radius: 5px;
    }

    #clearSavedSelections {
      background-color: #F44336;
      cursor: pointer;
      width: fit-content;
      height: fit-content;
      padding: 4px;
      margin: 1px;
      font-size: 17px;
      font-weight: bold;
      border-radius: 5px;
    }

    #hideCombinationTestBtn {
      background-color: #3079ed;
      cursor: pointer;
      position: absolute;
      left: 5.6%;
      width: fit-content;
      height: fit-content;
      padding: 4px;
      margin: 1px;
      font-size: 17px;
      font-weight: bold;
      border-radius: 5px;
    }

    .collapsible {
      background-color: #3f51b5;
      color: white;
      cursor: pointer;
      padding: 5px;
      width: 50%;
      border: none;
      text-align: center;
      outline: none;
      font-size: 16px;
      font-weight: bold;
    }

    .collapsible.active,
    .collapsible:hover {
      background-color: #f1f1f1;
      color: #050505;
      border: 3px #3f51b5 solid;
    }

    .collapsible:after {
      content: '\002B';
      font-weight: bold;
      float: right;
      margin-left: 5px;
    }

    .collapsible.active:after {
      content: "\2212";
      color: black;
      font-weight: bold;
      font-size: 15px;
    }


